  "verses": [
    {
      "n": 21,
      "column": "left",
      "text": "Preezajees/ un lihgſmo-\njeehs tu Eedoma Meita/ tu Ee-\ndſihwotaja eekſch tahs Semmes\nuſ/ tomehr tas Bifkeris nahks\npee tewim arridsan/ tu peedser-\nfees/ un tapſi atſegta.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Taws Noseegums irr pa\nGallam tu Zianas Meita/\nWiꞥſch ne liks tewi wairs ais-\nwest. Bet tawu Noseegumu/\nak tu Eedoma Meita! Wiꞥſch\npeemeklehs/ taws Grehkus\nWiꞥſch attlahs.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ta V. Modalla.\nJeremijus luhbs nofirſchu preeſch teem Tau-\ndim/ ka Deews pahr teem gribbetu attak ap-\nschehlotes: 1/ 21. Uu kad tee fawus Greh-\nkus nofirſchu noschehlotu: 16. Gribbetu\nWiꞥſch winnas attak ar Schehlastibu uhs,\nluhfoht un ispeſtiht: 22.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "B eminni KUNGS/ kas\nB mums notizzis irr/ ap-\nBraugi to/ un uhsluhko\nmuhfu Neewaschanu.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Muhta eemantojama Tee-\nfa irr Swescheem tapputi/muh-\nfu Nammi teem Sweschinee-\nkeem.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Mehs effam Bahrint bes\nTehwa/ muhfäs Mahtes irr ta\nka Atraitnes.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Muhfu Uhdens irr mume\npar Nandu jadser/ muhfu Mal-\nka mums par Maksu nahkahs.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Mehs tohpam wajati pahr\nRakin (pahr Galwu/) mehs ef-\nfam peekuffufchi/ Duffeschanas\nmums newaid.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Mehs effam padeiwufchees\nteem Egiptereem un Affireerein/\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Muhta Tehwi irr apgreh-\nkojfchees/ un tee ne irr wairs/ un\nmehs neffam winno Noseegu-\nmus.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Kalpi walda pahr mumſ/\nun neweens irr/ kas muhs no\nwinnu Rohkahin isglahbj.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Mums irr muhfu Maise\nar Likſtu muhfäs Dſihwibas ja-\natwedd/ ta Sohbina deht Tuks-\nneſi.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Muhta Alyda irr aptmet-\nlejſi ka Zepli no tahda breeſmiga\nBadda.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Tee irr tahs Seewas\neekſch Zianas apſmehjuſchi/ tahs\nZumprawas eekſch Juhda Pils-\nfahteem.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Tee Leeli-Kungi irr zaun\nwinno Rohku uhslahrti/ un to\nWezzajo Waigus tee ne irr Goh-\nda turrejschi.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Tohs Jaunektus irr tee\nmalt dsinnutſchi/ un tee Puifsch\nirr appakſch Malkas Nastahm\nkluppufschi.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Tee Wezzajee atſtahj no\nWahrtim/ un tee Jauneſti no\nwinnu Dseefminabm.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Muhfu Sirde Lithgfiniba\nirr pa Gallam/ muhfu Deescha-\nna irr par Noskumſchanu tap-\npuft.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Tas Krohnis muhfäs\nGalwas irr nokrittis/ ak waj\nmums! ka mehs ta effam greh-\nkojfchi.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Tapehz irr muhfu Sirde\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
